  '00481f0d-6046-4df1-895f-109611a22839',
  '168cee73-f1ba-486c-a41e-3d356b828b37',
  $$Angular Standalone Components — No More NgModule$$,
  $$Standalone components in Angular 14+ let you declare a component without belonging to any NgModule. Add standalone: true in the decorator and list imports directly. This removes the ceremony of shared modules and makes tree-shaking more predictable. Use bootstrapApplication() instead of platformBrowserDynamic() to bootstrap.$$,
  $$@Component({
  standalone: true,
  imports: [CommonModule, RouterModule],
  selector: 'app-root',
  template: '<router-outlet />'
})
export class AppComponent {}$$,
