VALUES (
  'fd205100-d411-4fae-845f-f632cb16b511',
  '168cee73-f1ba-486c-a41e-3d356b828b37',
  $$React useTransition — Keep UI Responsive During Heavy Updates$$,
  $$useTransition marks a state update as non-urgent, letting React interrupt it if a higher-priority update arrives (e.g. a keystroke). The hook returns [isPending, startTransition]. Wrap expensive state updates (filtering a large list, navigating between tabs) inside startTransition. The UI stays interactive while the transition runs in the background.$$,
  $$const [isPending, startTransition] = useTransition();

function handleTabChange(tab) {
  startTransition(() => setActiveTab(tab));
}$$,
