  '81c0bb72-a196-4143-8357-978645663842',
  '168cee73-f1ba-486c-a41e-3d356b828b37',
  $$React Server Components — What Actually Runs on the Server$$,
  $$React Server Components (RSC) run exclusively on the server and ship zero JS to the client. They can directly await database queries or fetch calls, read env vars, and access the filesystem. They cannot use state, effects, or browser APIs. Client Components opt in with 'use client' at the top — they hydrate on the browser and can still be imported inside Server Components.$$,
  $$// page.tsx — Server Component by default
export default async function Page() {
  const data = await db.query('SELECT * FROM posts');
  return <PostList posts={data} />;
}$$,
