-- Questions for interview 8700065c
INSERT INTO interviews.interview_questions (id, interview_id, question, answer, order_index, created_at)
VALUES (
  'd4c5521f-41ad-44a3-8823-bba850179f60',
  '8700065c-41ef-4487-9555-8839ad0f3322',
  $$When does OnPush NOT prevent a check from running?$$,
  $$When an event listener (click, input) fires inside the component, Angular still runs CD for that component and its ancestors. Also markForCheck() and async pipe always schedule a check.$$,
  1,
  '2026-04-11 04:37:38+00'
);
INSERT INTO interviews.interview_questions (id, interview_id, question, answer, order_index, created_at)
VALUES (
  'eafa8756-5bd7-4816-85ec-7b3dcb1afdfe',
  '8700065c-41ef-4487-9555-8839ad0f3322',
  $$How do Signals interact with OnPush?$$,
  $$Signals automatically call markForCheck() on any component that reads them during the last render cycle, so you get fine-grained reactivity without manually calling ChangeDetectorRef.$$,
  2,
  '2026-04-11 04:37:38+00'
);

INSERT INTO interviews.interviews (id, author_id, title, body, company, role, difficulty, embedding, type, is_active, created_at, updated_at)
