INSERT INTO interviews.interview_questions (id, interview_id, question, answer, order_index, created_at)
VALUES (
  'fd9b87d4-8865-4828-bdb5-2d3c6f52dd8e',
  '41d6f2e7-3ae4-43b7-abb6-38e3bbff6f42',
  $$What happens if you call forRoot() twice?$$,
  $$You get two Router instances, breaking navigation. Angular warns about this. Use RouterModule.forChild() in feature modules and always guard with a 'guard' provider if building a library.$$,
  1,
  '2026-04-11 04:37:38+00'
);
INSERT INTO interviews.interview_questions (id, interview_id, question, answer, order_index, created_at)
VALUES (
  'e07f9982-29dc-4612-9017-89c96b16b87c',
  '41d6f2e7-3ae4-43b7-abb6-38e3bbff6f42',
  $$How do you lazy-load a feature module?$$,
  $$Use loadChildren in the route config: { path: 'admin', loadChildren: () => import('./admin/admin.module').then(m => m.AdminModule) }. For standalone routes use loadComponent instead.$$,
  2,
  '2026-04-11 04:37:38+00'
);

