-- Questions for interview 34d4d7de
INSERT INTO interviews.interview_questions (id, interview_id, question, answer, order_index, created_at)
VALUES (
  'daf40db3-830f-4474-b408-3312f926ea85',
  '34d4d7de-8ada-4227-9909-92124adbffbc',
  $$Why should keys be stable and unique, not array indexes?$$,
  $$Using indexes as keys causes React to reuse DOM nodes incorrectly when items are reordered or deleted, leading to state being attached to the wrong component. Use stable IDs from your data instead.$$,
  1,
  '2026-04-11 04:37:38+00'
);
INSERT INTO interviews.interview_questions (id, interview_id, question, answer, order_index, created_at)
VALUES (
  'abe376b7-bade-4ac7-9d9a-1b7793ac9776',
  '34d4d7de-8ada-4227-9909-92124adbffbc',
  $$What is the purpose of the Fiber architecture over the old stack reconciler?$$,
  $$Fiber makes reconciliation interruptible. The old stack reconciler was synchronous and could block the main thread for large trees. Fiber assigns priority to work units and can pause, resume, or abort them — enabling features like useTransition and Suspense.$$,
  2,
  '2026-04-11 04:37:38+00'
);

