INSERT INTO interviews.interview_questions (id, interview_id, question, answer, order_index, created_at)
VALUES (
  '995121de-d9a3-4319-81d9-877240215373',
  '579d62d9-d3c5-4f74-8128-a4adaf7042d4',
  $$What is referential equality and why does it matter in React?$$,
  $$In JS, {} === {} is false even if the contents are identical. React.memo and hook dependency arrays compare by reference, so a new object/function on every render will still cause re-renders even if values are the same.$$,
  1,
  '2026-04-11 04:37:38+00'
);
INSERT INTO interviews.interview_questions (id, interview_id, question, answer, order_index, created_at)
VALUES (
  '64fa3aaa-036d-465c-9f6b-ec08a313c16c',
  '579d62d9-d3c5-4f74-8128-a4adaf7042d4',
  $$When would you NOT use useMemo?$$,
  $$For cheap computations, for values that change on every render anyway, or when the component is never re-rendered from a parent. The comparison and cache overhead can outweigh the savings for trivial operations.$$,
  2,
  '2026-04-11 04:37:38+00'
);

